class EngineConfig:
    """Builder for configuring and creating a GoudGame instance with provider selection."""

    def __init__(self):
        lib = get_lib()
        self._lib = lib
        self._handle = lib.goud_engine_config_create()

    def __del__(self):
        self.destroy()

    def set_title(self, title):
        """Sets the window title"""
        if not self._handle:
            raise RuntimeError('EngineConfig already consumed or destroyed')
        self._lib.goud_engine_config_set_title(self._handle, title.encode('utf-8'))
        return self

    def set_size(self, width, height):
        """Sets the window size in pixels"""
        if not self._handle:
            raise RuntimeError('EngineConfig already consumed or destroyed')
        self._lib.goud_engine_config_set_size(self._handle, width, height)
        return self

    def set_vsync(self, enabled):
        """Enables or disables vertical sync"""
        if not self._handle:
            raise RuntimeError('EngineConfig already consumed or destroyed')
        self._lib.goud_engine_config_set_vsync(self._handle, enabled)
        return self

    def set_fullscreen(self, enabled):
        """Enables or disables fullscreen mode"""
        if not self._handle:
            raise RuntimeError('EngineConfig already consumed or destroyed')
        self._lib.goud_engine_config_set_fullscreen(self._handle, enabled)
        return self

    def set_target_fps(self, fps):
        """Sets the target frames per second"""
        if not self._handle:
            raise RuntimeError('EngineConfig already consumed or destroyed')
        self._lib.goud_engine_config_set_target_fps(self._handle, fps)
        return self

    def set_fps_overlay(self, enabled):
        """Enables or disables the FPS debug overlay"""
        if not self._handle:
            raise RuntimeError('EngineConfig already consumed or destroyed')
        self._lib.goud_engine_config_set_fps_overlay(self._handle, enabled)
        return self

    def set_physics_debug(self, enabled):
        """Enables or disables physics debug visualization"""
        if not self._handle:
            raise RuntimeError('EngineConfig already consumed or destroyed')
        self._lib.goud_engine_config_set_physics_debug(self._handle, enabled)
        return self

    def set_physics_backend2_d(self, backend):
        """Selects the 2D physics backend used by the built game"""
        if not self._handle:
            raise RuntimeError('EngineConfig already consumed or destroyed')
        self._lib.goud_engine_config_set_physics_backend_2d(self._handle, int(backend))
        return self

    def build(self):
        """Consumes the config and creates a windowed GoudGame instance"""
        if not self._handle:
            raise RuntimeError('EngineConfig already consumed')
        ctx = self._lib.goud_engine_create(self._handle)
        self._handle = None
        if ctx._bits == 0xFFFFFFFFFFFFFFFF:
            raise RuntimeError('Failed to create engine context from EngineConfig')
        game = GoudGame.__new__(GoudGame)
        game._lib = self._lib
        game._ctx = ctx
        game._delta_time = 0.0
        game._title = ''
        game._frame_count = 0
        game._total_time = 0.0
        return game

    def destroy(self):
        """Frees the config without building"""
        if hasattr(self, '_handle') and self._handle:
            self._lib.goud_engine_config_destroy(self._handle)
            self._handle = None


class UiManager:
    """Immediate-mode UI manager for creating and managing UI node trees"""

    def __init__(self):
        lib = get_lib()
        self._lib = lib
        self._handle = lib.goud_ui_manager_create()
        if not self._handle:
            raise RuntimeError('Failed to create UiManager')

    def __del__(self):
        self.destroy()

    def destroy(self):
        if hasattr(self, '_handle') and self._handle:
            self._lib.goud_ui_manager_destroy(self._handle)
            self._handle = None

    def update(self):
        self._lib.goud_ui_manager_update(self._handle)

    def render(self):
        self._lib.goud_ui_manager_render(self._handle)

    def node_count(self):
        return self._lib.goud_ui_manager_node_count(self._handle)

    def create_node(self, component_type):
        return self._lib.goud_ui_create_node(self._handle, component_type)

    def remove_node(self, node_id):
        return self._lib.goud_ui_remove_node(self._handle, node_id)

    def set_parent(self, child_id, parent_id):
        return self._lib.goud_ui_set_parent(self._handle, child_id, parent_id)

    def get_parent(self, node_id):
        return self._lib.goud_ui_get_parent(self._handle, node_id)

    def get_child_count(self, node_id):
        return self._lib.goud_ui_get_child_count(self._handle, node_id)

    def get_child_at(self, node_id, index):
        return self._lib.goud_ui_get_child_at(self._handle, node_id, index)

    def set_widget(self, node_id, widget_kind):
        return self._lib.goud_ui_set_widget(self._handle, node_id, widget_kind)

    def set_style(self, node_id, style):
        ffi_style = FfiUiStyle()
        ffi_style.has_background_color = bool(style.has_background_color)
        ffi_style.background_color = FfiColor(style.background_color.r, style.background_color.g, style.background_color.b, style.background_color.a)
        ffi_style.has_foreground_color = bool(style.has_foreground_color)
        ffi_style.foreground_color = FfiColor(style.foreground_color.r, style.foreground_color.g, style.foreground_color.b, style.foreground_color.a)
        ffi_style.has_border_color = bool(style.has_border_color)
        ffi_style.border_color = FfiColor(style.border_color.r, style.border_color.g, style.border_color.b, style.border_color.a)
        ffi_style.has_border_width = bool(style.has_border_width)
        ffi_style.border_width = style.border_width
        ffi_style.has_font_family = bool(style.has_font_family)
        font_family = '' if style.font_family is None else style.font_family
        font_family_bytes = font_family.encode('utf-8') if style.has_font_family else b''
        font_family_buf = ctypes.create_string_buffer(font_family_bytes, len(font_family_bytes)) if font_family_bytes else None
        ffi_style.font_family_ptr = ctypes.cast(font_family_buf, ctypes.c_void_p).value if font_family_bytes else None
        ffi_style.font_family_len = len(font_family_bytes)
        ffi_style.has_font_size = bool(style.has_font_size)
        ffi_style.font_size = style.font_size
        ffi_style.has_texture_path = bool(style.has_texture_path)
        texture_path = '' if style.texture_path is None else style.texture_path
        texture_path_bytes = texture_path.encode('utf-8') if style.has_texture_path else b''
        texture_path_buf = ctypes.create_string_buffer(texture_path_bytes, len(texture_path_bytes)) if texture_path_bytes else None
        ffi_style.texture_path_ptr = ctypes.cast(texture_path_buf, ctypes.c_void_p).value if texture_path_bytes else None
        ffi_style.texture_path_len = len(texture_path_bytes)
        ffi_style.has_widget_spacing = bool(style.has_widget_spacing)
        ffi_style.widget_spacing = style.widget_spacing
        return self._lib.goud_ui_set_style(self._handle, node_id, ctypes.byref(ffi_style))

    def set_label_text(self, node_id, text):
        text = '' if text is None else text
        text_bytes = text.encode('utf-8')
        text_buf = ctypes.create_string_buffer(text_bytes, len(text_bytes)) if text_bytes else None
        text_ptr = ctypes.cast(text_buf, ctypes.POINTER(ctypes.c_uint8)) if text_bytes else ctypes.POINTER(ctypes.c_uint8)()
        return self._lib.goud_ui_set_label_text(self._handle, node_id, text_ptr, len(text_bytes))

    def set_button_enabled(self, node_id, enabled):
        return self._lib.goud_ui_set_button_enabled(self._handle, node_id, enabled)

    def set_image_texture_path(self, node_id, path):
        path = '' if path is None else path
        path_bytes = path.encode('utf-8')
        path_buf = ctypes.create_string_buffer(path_bytes, len(path_bytes)) if path_bytes else None
        path_ptr = ctypes.cast(path_buf, ctypes.POINTER(ctypes.c_uint8)) if path_bytes else ctypes.POINTER(ctypes.c_uint8)()
        return self._lib.goud_ui_set_image_texture_path(self._handle, node_id, path_ptr, len(path_bytes))

    def set_slider(self, node_id, min_value, max_value, value, enabled):
        return self._lib.goud_ui_set_slider(self._handle, node_id, min_value, max_value, value, enabled)

    def event_count(self):
        return self._lib.goud_ui_event_count(self._handle)

    def event_read(self, index):
        event = FfiUiEvent()
        status = self._lib.goud_ui_event_read(self._handle, index, ctypes.byref(event))
        if status <= 0:
            return None
        return UiEvent(event.event_kind, event.node_id, event.previous_node_id, event.current_node_id)

    # Convenience widget helpers
    def create_panel(self):
        return self.create_node(0)

    def create_label(self, text):
        node = self.create_node(2)
        self.set_label_text(node, text)
        return node

    def create_button(self, enabled = True):
        node = self.create_node(1)
        self.set_button_enabled(node, enabled)
        return node

    def create_image(self, path):
        node = self.create_node(3)
        self.set_image_texture_path(node, path)
        return node

    def create_slider(self, min_value, max_value, value, enabled = True):
        node = self.create_node(4)
        self.set_slider(node, min_value, max_value, value, enabled)
        return node
